/// Create a multi-algorithm verifier supporting both HMAC and RSA.
pub fn create_multi_algorithm_verifier(
    hmac_secret: &[u8],
    rsa_public_key_pem: Option<&[u8]>,
    ec_public_key_pem: Option<&[u8]>,
    issuer: Option<String>,
    audience: Option<String>,
) -> JwtVerifier {
    let mut signing_keys = vec![
        SigningKeyConfig {
            algorithm: Algorithm::HS256,
            key: KeyType::Secret(hmac_secret.to_vec()),
        },
        SigningKeyConfig {
            algorithm: Algorithm::HS384,
            key: KeyType::Secret(hmac_secret.to_vec()),
        },
        SigningKeyConfig {
            algorithm: Algorithm::HS512,
            key: KeyType::Secret(hmac_secret.to_vec()),
        },
    ];

    if let Some(rsa_pem) = rsa_public_key_pem {
        signing_keys.extend(vec![
            SigningKeyConfig {
                algorithm: Algorithm::RS256,
                key: KeyType::RsaPem(rsa_pem.to_vec()),
            },
            SigningKeyConfig {
                algorithm: Algorithm::RS384,
                key: KeyType::RsaPem(rsa_pem.to_vec()),
            },
            SigningKeyConfig {
                algorithm: Algorithm::RS512,
                key: KeyType::RsaPem(rsa_pem.to_vec()),
            },
        ]);
    }

    if let Some(ec_pem) = ec_public_key_pem {
        signing_keys.extend(vec![
            SigningKeyConfig {
                algorithm: Algorithm::ES256,
                key: KeyType::EcPem(ec_pem.to_vec()),
            },
            SigningKeyConfig {
                algorithm: Algorithm::ES384,
                key: KeyType::EcPem(ec_pem.to_vec()),
            },
        ]);
    }

    let config = JwtVerifierConfig {
        signing_keys,
        required_issuer: issuer,
        required_audience: audience,
        leeway_seconds: 30,
    };
    JwtVerifier::new(config)
}

